/**
 * Product catalog for Sri Venkata Sai Enterprises.
 *
 * Prices are indicative MRPs sourced from public listings (to be verified &
 * updated by the owner). The "priceOnEnquiry" flag, when true, hides the price
 * in the UI and shows "Price on Enquiry" / "Ask on WhatsApp".
 *
 * Images live under /public/images/products/<imageFolder>/1.<ext>. The
 * `image` field points to the cover image; the gallery reads the folder.
 */

export type ProductCategory =
  | "new-arrival"
  | "best-seller"
  | "deal"
  | "flagship"
  | "budget"
  | "accessory";

export type ProductType =
  | "smartphone"
  | "tablet"
  | "earbuds"
  | "accessory"
  | "feature-phone"
  | "router";

export type StockStatus = "inStock" | "limited" | "outOfStock";

export interface ProductVariant {
  ram: string;
  storage: string;
  /** Price in INR. Omit (undefined) when price is on enquiry only. */
  price?: number;
  originalPrice?: number;
  /** Per-variant Amazon-specific price (when available). */
  amazonPrice?: number;
  /** Per-variant Flipkart-specific price (when available). */
  flipkartPrice?: number;
  amazonUrl?: string;
  flipkartUrl?: string;
}

export interface ProductColor {
  name: string;
  hex: string;
}

export interface Product {
  id: string;
  name: string;
  slug: string;
  brand: string;
  brandSlug: string;
  /** Folder name under /public/images/products/. */
  imageFolder: string;
  type: ProductType;
  category: ProductCategory;
  stock: StockStatus;
  /** Cover image. */
  image: string;
  description: string;
  colors: ProductColor[];
  variants: ProductVariant[];
  specifications: { label: string; value: string }[];
  featured: boolean;
  tags: string[];
  price?: number;
  originalPrice?: number;
  /** When true, price is hidden — enquiry only. */
  priceOnEnquiry?: boolean;
  /** Live Flipkart price written by the 6h price-sync (authoritative storefront price). */
  flipkartPrice?: number;
  /** Live Amazon price written by the 6h price-sync (only when an amazonUrl exists). */
  amazonPrice?: number;
  amazonUrl?: string;
  flipkartUrl?: string;
  /** Legacy: derived from variants.ram / variants.storage */
  ramOptions?: string[];
  storageOptions?: string[];
}

/** Build a product entry; resolves `image` from the imageFolder automatically. */
function p(input: Omit<Product, "image"> & { image?: string }): Product {
  return {
    ...input,
    image: input.image ?? `/images/products/${input.imageFolder}/1.webp`,
  };
}

